package provider

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"time"
)

// Embedder generates vector embeddings from text.
type Embedder interface {
	Embed(ctx context.Context, text string) ([]float32, error)
	Dimensions() int
}

const (
	openAIEmbeddingURL    = "https://api.openai.com/v1/embeddings"
	openAIEmbeddingModel  = "text-embedding-3-small"
	embeddingDimensions   = 1536
	embeddingTimeout      = 30 * time.Second
	maxEmbeddingInputLen  = 30000 // rough char limit to stay under 8191 tokens
)

// OpenAIEmbedder generates embeddings via the OpenAI API.
type OpenAIEmbedder struct {
	apiKey string
	model  string
	client *http.Client
}

// OpenAIEmbedderOption configures an OpenAIEmbedder.
type OpenAIEmbedderOption func(*OpenAIEmbedder)

// WithEmbeddingModel sets a custom model name.
func WithEmbeddingModel(model string) OpenAIEmbedderOption {
	return func(e *OpenAIEmbedder) { e.model = model }
}

// WithEmbeddingHTTPClient sets a custom HTTP client (useful for testing).
func WithEmbeddingHTTPClient(c *http.Client) OpenAIEmbedderOption {
	return func(e *OpenAIEmbedder) { e.client = c }
}

// NewOpenAIEmbedder creates an OpenAI-based embedder.
func NewOpenAIEmbedder(apiKey string, opts ...OpenAIEmbedderOption) *OpenAIEmbedder {
	e := &OpenAIEmbedder{
		apiKey: apiKey,
		model:  openAIEmbeddingModel,
		client: &http.Client{Timeout: embeddingTimeout},
	}
	for _, opt := range opts {
		opt(e)
	}
	return e
}

// Dimensions returns the embedding vector size.
func (e *OpenAIEmbedder) Dimensions() int { return embeddingDimensions }

type embeddingRequest struct {
	Input string `json:"input"`
	Model string `json:"model"`
}

type embeddingResponse struct {
	Data []struct {
		Embedding []float32 `json:"embedding"`
	} `json:"data"`
	Error *struct {
		Message string `json:"message"`
	} `json:"error"`
}

// Embed generates a vector embedding for the given text.
func (e *OpenAIEmbedder) Embed(ctx context.Context, text string) ([]float32, error) {
	if text == "" {
		return nil, fmt.Errorf("provider: embed: empty input")
	}

	// Truncate to avoid token limit errors
	if len(text) > maxEmbeddingInputLen {
		text = text[:maxEmbeddingInputLen]
	}

	body, err := json.Marshal(embeddingRequest{
		Input: text,
		Model: e.model,
	})
	if err != nil {
		return nil, fmt.Errorf("provider: embed: marshal request: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, openAIEmbeddingURL, bytes.NewReader(body))
	if err != nil {
		return nil, fmt.Errorf("provider: embed: build request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Authorization", "Bearer "+e.apiKey)

	resp, err := e.client.Do(req)
	if err != nil {
		return nil, fmt.Errorf("provider: embed: http: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	respBody, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("provider: embed: read response: %w", err)
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("provider: embed: api status %d: %s", resp.StatusCode, string(respBody))
	}

	var result embeddingResponse
	if err := json.Unmarshal(respBody, &result); err != nil {
		return nil, fmt.Errorf("provider: embed: unmarshal response: %w", err)
	}

	if result.Error != nil {
		return nil, fmt.Errorf("provider: embed: api error: %s", result.Error.Message)
	}

	if len(result.Data) == 0 || len(result.Data[0].Embedding) == 0 {
		return nil, fmt.Errorf("provider: embed: empty embedding in response")
	}

	return result.Data[0].Embedding, nil
}

package worker

import (
	"context"
	"log/slog"

	"github.com/google/uuid"
	"github.com/riverqueue/river"
)

// ClassifyArgs are the arguments for an auto-classification job.
type ClassifyArgs struct {
	ItemID  uuid.UUID `json:"item_id"`
	Content string    `json:"content"`
}

func (ClassifyArgs) Kind() string { return "classify" }

// ClassifyWorker auto-extracts metadata (category, people, topics) via LLM.
type ClassifyWorker struct {
	river.WorkerDefaults[ClassifyArgs]
}

func (w *ClassifyWorker) Work(ctx context.Context, job *river.Job[ClassifyArgs]) error {
	slog.InfoContext(ctx, "worker: classify: processing",
		"item_id", job.Args.ItemID,
		"content_len", len(job.Args.Content),
	)
	return nil
}

import { useState } from 'react'
import { Container, Title, TextInput, Stack, Card, Text, Group, Badge, Loader } from '@mantine/core'
import { Search as SearchIcon } from 'lucide-react'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'

interface SearchItem {
  id: string
  type: string
  title: string | null
  contentText: string | null
  tags: string[]
  source: string
  sourceUrl: string | null
  capturedAt: string
}

interface SearchData {
  search: {
    items: SearchItem[]
    total: number
    hasMore: boolean
  }
}

const SearchQuery = graphql(`
  query Search($query: String!, $limit: Int) {
    search(query: $query, limit: $limit) {
      items {
        id
        type
        title
        contentText
        tags
        source
        sourceUrl
        capturedAt
      }
      total
      hasMore
    }
  }
`)

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString()
}

export function Search() {
  const [query, setQuery] = useState('')
  const [submitted, setSubmitted] = useState('')

  const [result] = useQuery<SearchData>({
    query: SearchQuery,
    variables: { query: submitted, limit: 20 },
    pause: !submitted,
  })

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setSubmitted(query.trim())
  }

  return (
    <Container size="md" py="xl">
      <Stack gap="lg">
        <Title order={2}>Search</Title>

        <form onSubmit={handleSubmit}>
          <TextInput
            placeholder="Search your knowledge base..."
            leftSection={<SearchIcon size={16} />}
            value={query}
            onChange={(e) => setQuery(e.currentTarget.value)}
            size="md"
          />
        </form>

        {result.fetching && <Loader size="sm" />}

        {result.error && (
          <Text c="red" fz="sm">
            {result.error.message}
          </Text>
        )}

        {result.data && (
          <Stack gap="sm">
            <Text fz="sm" c="dimmed">
              {result.data.search.total} result{result.data.search.total !== 1 ? 's' : ''}
            </Text>

            {result.data.search.items.map((item) => (
              <Card key={item.id} shadow="xs" padding="md" radius="md" withBorder>
                <Group justify="space-between" mb="xs">
                  <Text fw={600}>{item.title ?? 'Untitled'}</Text>
                  <Badge size="sm" variant="light">
                    {item.type}
                  </Badge>
                </Group>
                {item.contentText && (
                  <Text fz="sm" c="dimmed" lineClamp={2}>
                    {item.contentText}
                  </Text>
                )}
                <Group gap="xs" mt="xs">
                  {item.tags.map((tag) => (
                    <Badge key={tag} size="xs" variant="outline">
                      {tag}
                    </Badge>
                  ))}
                  <Text fz="xs" c="dimmed" ml="auto">
                    {formatDate(item.capturedAt)}
                  </Text>
                </Group>
              </Card>
            ))}
          </Stack>
        )}

        {submitted && !result.fetching && result.data?.search.total === 0 && (
          <Text c="dimmed" ta="center" py="xl">
            No results found.
          </Text>
        )}
      </Stack>
    </Container>
  )
}

package provider

import (
	"context"
	"io"
)

// TranscribeOpts holds options for a transcription request.
type TranscribeOpts struct {
	Language string // BCP-47 language code, e.g. "en"
	Format   string // audio format hint: "wav", "mp3", "webm", "m4a", "ogg", "mp4", "flac"
}

// Transcriber transcribes audio to text.
type Transcriber interface {
	Transcribe(ctx context.Context, audio io.Reader, opts TranscribeOpts) (string, error)
}

package worker

import (
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/internal/item"
	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
)

// Deps holds dependencies that workers need for processing jobs.
type Deps struct {
	Pool        *pgxpool.Pool
	Storage     *storage.Client // nil if S3 not configured
	Transcriber provider.Transcriber
	Embedder    provider.Embedder // nil if no embedding provider configured
}

// Registry holds registered workers and allows setting the River client after
// creation (resolves the circular dependency: workers need RiverClient, but
// RiverClient needs the workers collection).
type Registry struct {
	Workers        *river.Workers
	pageFetchWorker   *PageFetchWorker
	transcribeWorker  *TranscribeWorker
}

// SetRiverClient sets the River client on workers that need to enqueue follow-up jobs.
func (reg *Registry) SetRiverClient(client *river.Client[pgx.Tx]) {
	reg.pageFetchWorker.RiverClient = client
	reg.transcribeWorker.RiverClient = client
}

// NewRegistry creates a Registry with all job types registered.
func NewRegistry(deps Deps) *Registry {
	items := item.New(deps.Pool)

	pfw := &PageFetchWorker{Items: items, Storage: deps.Storage}
	tw := &TranscribeWorker{
		Storage:     deps.Storage,
		Transcriber: deps.Transcriber,
		Pool:        deps.Pool,
	}

	workers := river.NewWorkers()
	river.AddWorker(workers, pfw)
	river.AddWorker(workers, tw)
	river.AddWorker(workers, &EmbedWorker{
		Pool:     deps.Pool,
		Embedder: deps.Embedder,
	})
	river.AddWorker(workers, &ClassifyWorker{})
	river.AddWorker(workers, &S3UploadWorker{})

	return &Registry{
		Workers:          workers,
		pageFetchWorker:  pfw,
		transcribeWorker: tw,
	}
}

package config

import (
	"fmt"
	"log/slog"
	"os"
	"time"

	"github.com/caarlos0/env/v11"
)

// Config holds all application configuration loaded from environment variables.
type Config struct {
	Host string `env:"HOST" envDefault:"0.0.0.0"`
	Port int    `env:"PORT" envDefault:"8081"`

	DatabaseURL string `env:"DATABASE_URL,required"`
	JWTSecret   string        `env:"JWT_SECRET,required"` //nolint:gosec // config field name, not a hardcoded secret
	JWTExpiry   time.Duration `env:"JWT_EXPIRY" envDefault:"24h"`

	S3Endpoint       string `env:"S3_ENDPOINT"`
	S3Bucket         string `env:"S3_BUCKET" envDefault:"flotsam-dev"`
	S3AccessKey      string `env:"S3_ACCESS_KEY"`
	S3SecretKey      string `env:"S3_SECRET_KEY"`
	S3Region         string `env:"S3_REGION" envDefault:"us-east-1"`
	S3ForcePathStyle bool   `env:"S3_FORCE_PATH_STYLE" envDefault:"false"`

	OpenAIAPIKey   string `env:"OPENAI_API_KEY"`
	EmbeddingModel string `env:"EMBEDDING_MODEL" envDefault:"text-embedding-3-small"`
	OllamaURL      string `env:"OLLAMA_URL"`

	WhisperModel      string `env:"WHISPER_MODEL" envDefault:"whisper-1"`
	WhisperLocalBin   string `env:"WHISPER_LOCAL_BIN"`
	WhisperLocalModel string `env:"WHISPER_LOCAL_MODEL"`
	MaxUploadSize     int64  `env:"MAX_UPLOAD_SIZE" envDefault:"52428800"` // 50MB

	LogLevel  string `env:"LOG_LEVEL" envDefault:"info"`
	LogFormat string `env:"LOG_FORMAT" envDefault:"json"`

	Env string `env:"ENV" envDefault:"development"`

	CORSOrigins string `env:"CORS_ORIGINS"`

	GQLPlayground    bool `env:"GRAPHQL_PLAYGROUND" envDefault:"false"`
	GQLIntrospection bool `env:"GRAPHQL_INTROSPECTION" envDefault:"false"`

	MCPEnabled bool `env:"MCP_ENABLED" envDefault:"true"`

	RateLimitEnabled     bool `env:"RATE_LIMIT_ENABLED" envDefault:"true"`
	RateLimitGraphQL     int  `env:"RATE_LIMIT_GRAPHQL" envDefault:"60"`
	RateLimitGraphQLAuth int  `env:"RATE_LIMIT_GRAPHQL_AUTH" envDefault:"120"`
	RateLimitMCP         int  `env:"RATE_LIMIT_MCP" envDefault:"120"`

	ShutdownTimeout time.Duration `env:"SHUTDOWN_TIMEOUT" envDefault:"15s"`
}

// Load parses and validates configuration from environment variables.
func Load() (*Config, error) {
	cfg := &Config{}
	if err := env.Parse(cfg); err != nil {
		return nil, fmt.Errorf("config: %w", err)
	}
	return cfg, nil
}

// Addr returns the host:port bind address.
func (c *Config) Addr() string {
	return fmt.Sprintf("%s:%d", c.Host, c.Port)
}

// ParseLogLevel converts a log level string to the corresponding slog.Level.
func ParseLogLevel(s string) slog.Level {
	switch s {
	case "trace":
		return slog.Level(-8) // custom TRACE level
	case "debug":
		return slog.LevelDebug
	case "warn":
		return slog.LevelWarn
	case "error":
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

// LogHandler returns an slog.Handler configured per LOG_LEVEL and LOG_FORMAT.
func (c *Config) LogHandler() slog.Handler {
	level := ParseLogLevel(c.LogLevel)
	opts := &slog.HandlerOptions{
		Level:     level,
		AddSource: c.Env == "development",
	}

	if c.LogFormat == "text" {
		return slog.NewTextHandler(os.Stderr, opts)
	}
	return slog.NewJSONHandler(os.Stderr, opts)
}

